let wf = $input.item.json;
let report = { wf_name: wf.name, correcoes: [], erros_criticos: [], seguro_corrigir: false, tokens_consumidos: 0, changed: false };
let wf_str = JSON.stringify(wf);

// Erro 1: Dominio Manus
if (wf_str.match(/api\.manus\.(gg|gq|ia|ai\/v1)/)) {
  wf_str = wf_str.replace(/api\.manus\.(gg|gq|ia|ai\/v1)/g, 'api.manus.ai/v2');
  report.correcoes.push("Domínio Manus restaurado para api.manus.ai/v2");
  report.changed = true;
}

// Erro 5: Nomes comerciais
if (wf_str.includes("Gatekeeper") && !wf_str.includes("DL GateKeeper")) {
  wf_str = wf_str.replace(/Gatekeeper/g, "DL GateKeeper");
  report.correcoes.push("Gatekeeper corrigido para DL GateKeeper");
  report.changed = true;
}
if (wf_str.includes("Fortress") && !wf_str.includes("DL Fortress")) {
  wf_str = wf_str.replace(/Fortress/g, "DL Fortress");
  report.correcoes.push("Fortress corrigido para DL Fortress");
  report.changed = true;
}
if (wf_str.includes("DL Ignis")) {
  wf_str = wf_str.replace(/DL Ignis/g, "DL Alerta");
  report.correcoes.push("DL Ignis corrigido para DL Alerta");
  report.changed = true;
}
if (wf_str.includes("Mult•Grill Express")) {
  wf_str = wf_str.replace(/Mult•Grill Express/g, "DL Suporte Grill’s");
  report.correcoes.push("Marca corrigida para DL Suporte Grill’s");
  report.changed = true;
}

if (wf.name.includes("070")) {
   let hasKey = wf_str.includes("x-manus-api-key");

   // Erro 2: Header Manus ausente ou Bearer
   if (wf_str.includes("Authorization: Bearer") && hasKey) {
     wf_str = wf_str.replace(/Authorization: Bearer/g, "x-manus-api-key");
     report.correcoes.push("Header Manus restaurado para x-manus-api-key");
     report.changed = true;
   } else if (!hasKey) {
     report.erros_criticos.push("Chave Manus ausente (x-manus-api-key não encontrada). Correção bloqueada para preservar credencial.");
   }

   if (!wf_str.includes("structured_output_schema")) report.erros_criticos.push("structured_output_schema ausente");
   if (!wf_str.includes("agent_profile")) report.erros_criticos.push("agent_profile ausente");
   if (!wf_str.includes("interactive_mode")) report.erros_criticos.push("interactive_mode ausente");

   // Erro 3: Polling
   if (wf_str.includes("task.create") && wf_str.includes("task.listMessages") && !wf_str.includes("task.detail")) {
     // Structural change blocked due to complexity. Escalated to Critical.
     report.erros_criticos.push("Ausência de polling real detectada (falta task.detail). Correção ignorada devido a complexidade estrutural. Requer intervenção manual.");
   }
}

// Erro 4: Telegram Bloqueio
if (wf_str.includes("Aguardando Aprovação Telegram") || wf_str.includes("Aprovação Manual Telegram")) {
  // Structural change blocked due to complexity. Escalated to Critical.
  report.erros_criticos.push("Telegram configurado como bloqueio/aprovação em fluxo automático. Correção ignorada devido a complexidade estrutural. Requer intervenção manual.");
}

if (report.correcoes.length > 0 && report.erros_criticos.length === 0) {
  report.seguro_corrigir = true;
}

return { json: { report: report, workflow: JSON.parse(wf_str) } };

